const e=t=>`https://scholar.google.com/scholar?q=${encodeURIComponent(t)}`,a=[{id:"transformer",title:"Attention Is All You Need",authors:"Vaswani, Shazeer, Parmar, et al.",year:2017,venue:"NeurIPS",topic:"Architecture",difficulty:"Advanced",link:"https://arxiv.org/abs/1706.03762",summary:"Replaced recurrence and convolution with self-attention alone, letting every token attend to every other token in parallel. The Transformer made long-range dependencies cheap to model and training trivially parallelizable, and it became the backbone of nearly every modern language and vision model.",ideas:["Scaled dot-product self-attention over the full sequence","Multi-head attention to read several relation subspaces at once","Positional encodings inject order without recurrence","Encoder-decoder stacks of identical residual blocks"],steps:[{title:"Tokenize the input",detail:"Split text into subword tokens and map each to an integer id."},{title:"Embed plus positional encoding",detail:"Look up a learned vector per token and add sinusoidal position signals so order survives.",block:"pos"},{title:"Scaled dot-product attention",detail:"Score each query against every key, scale by sqrt(d), softmax, then weight the values.",block:"attn"},{title:"Multi-head attention",detail:"Run several attention heads in parallel to capture different relation subspaces, then concat.",block:"attn"},{title:"Position-wise feed-forward",detail:"Apply the same two-layer MLP independently to every position.",block:"ffn"},{title:"Add and LayerNorm residuals",detail:"Wrap each sublayer in a residual connection followed by layer normalization.",block:"ffn"},{title:"Stack encoder and decoder",detail:"Repeat the block N times; the decoder adds masked self-attention plus cross-attention to the encoder.",block:"cross"},{title:"Project to vocabulary",detail:"Linear layer plus softmax turns the final states into next-token probabilities.",block:"cross"}],diagram:"transformer"},{id:"alexnet",title:"ImageNet Classification with Deep Convolutional Neural Networks",authors:"Krizhevsky, Sutskever, Hinton",year:2012,venue:"NeurIPS",topic:"Vision",difficulty:"Intermediate",link:e("ImageNet Classification with Deep Convolutional Neural Networks Krizhevsky"),summary:"AlexNet halved the ImageNet error rate overnight and proved that deep CNNs trained on GPUs could beat hand-engineered vision pipelines. It kicked off the deep-learning era in computer vision.",ideas:["Deep CNN trained end to end on two GPUs","ReLU activations for far faster convergence","Dropout in the dense layers to fight overfitting","Data augmentation and local response normalization"],steps:[{title:"Feed the raw image",detail:"Take a 224x224 RGB crop as input, no hand-engineered features.",block:0},{title:"Stack convolutional layers",detail:"Five conv layers learn edges, textures, then object parts directly from pixels.",block:1},{title:"Apply ReLU activations",detail:"Rectified linear units replace saturating tanh, training several times faster.",block:1},{title:"Downsample with max pooling",detail:"Overlapping max pools shrink spatial size and add translation tolerance.",block:2},{title:"Regularize the dense head",detail:"Two fully connected layers use dropout to break fragile co-adaptations.",block:3},{title:"Classify with softmax",detail:"A 1000-way softmax outputs the ImageNet class distribution.",block:4}],diagram:"flow",flow:["Input image","Conv + ReLU x5","Max pool","Dense + Dropout","1000-way softmax"]},{id:"resnet",title:"Deep Residual Learning for Image Recognition",authors:"He, Zhang, Ren, Sun",year:2015,venue:"CVPR",topic:"Vision",difficulty:"Intermediate",link:"https://arxiv.org/abs/1512.03385",summary:"Residual connections let layers learn a delta on top of their input, so gradients flow cleanly through hundreds of layers. ResNet trained networks an order of magnitude deeper than before and won ImageNet 2015.",ideas:["Identity skip connections add the input to the block output","Reformulates layers to learn residuals F(x) = H(x) - x","Enables 50-, 101-, and 152-layer networks that still train","Bottleneck blocks keep deep variants affordable"],steps:[{title:"Take the block input x",detail:"Each residual block receives the activation from the previous block.",block:"in"},{title:"Transform through weight layers",detail:"Two or three conv layers with ReLU compute the residual function F(x).",block:"weight"},{title:"Carry the identity skip",detail:"A parallel shortcut copies x forward unchanged, with no extra parameters.",block:"skip"},{title:"Add residual to identity",detail:"Output is F(x) + x, so the block only has to learn the difference.",block:"add"},{title:"Use bottlenecks when deep",detail:"1x1 conv reduces then restores channels to keep 50-152 layer nets affordable.",block:"weight"},{title:"Stack to great depth",detail:"Clean gradient flow through skips lets hundreds of layers train without degrading.",block:"add"}],diagram:"resnet"},{id:"adam",title:"Adam: A Method for Stochastic Optimization",authors:"Kingma, Ba",year:2014,venue:"ICLR",topic:"Optimization",difficulty:"Intermediate",link:"https://arxiv.org/abs/1412.6980",summary:"Adam combined momentum with per-parameter adaptive learning rates and bias correction into one robust optimizer that works well out of the box. It is the default choice for training most deep networks.",ideas:["First-moment (momentum) estimate of the gradient","Second-moment estimate scales each step adaptively","Bias correction fixes early-step underestimation","Little tuning needed across very different problems"],steps:[{title:"Compute the gradient",detail:"Backprop gives the gradient g of the loss for the current mini-batch.",block:0},{title:"Update the first moment",detail:"Exponential moving average m tracks the mean gradient direction (momentum).",block:1},{title:"Update the second moment",detail:"Exponential moving average v tracks squared gradients to gauge per-parameter scale.",block:1},{title:"Bias-correct the estimates",detail:"Divide m and v by (1 - beta^t) to fix their bias toward zero early in training.",block:2},{title:"Take the adaptive step",detail:"Update theta -= lr * m_hat / (sqrt(v_hat) + eps), small steps where gradients are noisy.",block:3}],diagram:"flow",flow:["Gradient g","Update m, v","Bias-correct","Step theta -= lr * m / sqrt(v)"]},{id:"bert",title:"BERT: Pre-training of Deep Bidirectional Transformers",authors:"Devlin, Chang, Lee, Toutanova",year:2018,venue:"NAACL",topic:"Language",difficulty:"Advanced",link:"https://arxiv.org/abs/1810.04805",summary:"BERT pre-trained a deep bidirectional Transformer on masked-language and next-sentence objectives, then fine-tuned the same weights for many tasks. The pretrain-then-finetune recipe became the standard for NLP.",ideas:["Masked language modeling reads context from both sides","Next-sentence prediction for pair-level understanding","One pre-trained model fine-tunes to many downstream tasks","WordPiece tokenization with special CLS and SEP tokens"],steps:[{title:"WordPiece tokenize",detail:"Split text into subwords and prepend a CLS token, separate segments with SEP.",block:0},{title:"Mask random tokens",detail:"Hide 15 percent of tokens; the model must predict them from both-side context.",block:0},{title:"Encode bidirectionally",detail:"A deep Transformer encoder attends left and right at once, unlike a left-to-right LM.",block:1},{title:"Predict masks and next sentence",detail:"Train on masked-token recovery plus a next-sentence classification objective.",block:2},{title:"Fine-tune for the task",detail:"Add a small task head and update all weights on the labeled downstream data.",block:3}],diagram:"flow",flow:["Masked tokens","Bidirectional encoder","Contextual vectors","Fine-tune head"]},{id:"gan",title:"Generative Adversarial Networks",authors:"Goodfellow, Pouget-Abadie, Mirza, et al.",year:2014,venue:"NeurIPS",topic:"Generative",difficulty:"Advanced",link:"https://arxiv.org/abs/1406.2661",summary:"GANs frame generation as a two-player game: a generator forges samples while a discriminator tries to spot fakes. Trained together, the generator learns to produce strikingly realistic data without an explicit likelihood.",ideas:["Generator maps noise to data-space samples","Discriminator scores real versus generated","Minimax objective drives both networks to improve","No explicit density needed for sharp samples"],steps:[{title:"Sample noise z",detail:"Draw a random latent vector from a simple prior such as a Gaussian.",block:0},{title:"Generate a fake sample",detail:"The generator network maps z into a candidate sample in data space.",block:1},{title:"Mix real and fake",detail:"Pair generated samples with real training examples for the critic.",block:2},{title:"Discriminate real vs fake",detail:"The discriminator outputs the probability that each input is real.",block:3},{title:"Backprop the minimax game",detail:"Update the discriminator to catch fakes and the generator to fool it.",block:4},{title:"Reach equilibrium",detail:"At convergence the generator matches the data and the critic is at chance.",block:4}],diagram:"flow",flow:["Noise z","Generator","Fake sample","Discriminator","Real / Fake"]},{id:"word2vec",title:"Efficient Estimation of Word Representations in Vector Space",authors:"Mikolov, Chen, Corrado, Dean",year:2013,venue:"ICLR Workshop",topic:"Language",difficulty:"Beginner",link:"https://arxiv.org/abs/1301.3781",summary:"Word2Vec learned dense word vectors so cheaply that whole vocabularies could be trained on billions of words. The resulting embeddings captured analogies like king - man + woman = queen as vector arithmetic.",ideas:["Skip-gram predicts context words from a center word","CBOW predicts a word from its surrounding context","Negative sampling makes training scale to huge corpora","Linear structure encodes semantic and syntactic analogies"],steps:[{title:"Slide a context window",detail:"Pick a center word and the words within a few positions around it.",block:0},{title:"Look up the embedding",detail:"Map the center word id to its current dense vector.",block:1},{title:"Predict the neighbours",detail:"Skip-gram scores how likely each context word is given the center vector.",block:2},{title:"Sample negatives",detail:"Contrast true context words against a few random words to avoid a full softmax.",block:2},{title:"Update the vectors",detail:"Nudge embeddings so co-occurring words land closer, encoding analogies linearly.",block:3}],diagram:"flow",flow:["Center word","Embedding lookup","Predict context","Dense word vectors"]},{id:"dropout",title:"Dropout: A Simple Way to Prevent Neural Networks from Overfitting",authors:"Srivastava, Hinton, Krizhevsky, et al.",year:2014,venue:"JMLR",topic:"Regularization",difficulty:"Beginner",link:e("Dropout A Simple Way to Prevent Neural Networks from Overfitting Srivastava"),summary:"Dropout randomly zeroes units during training, forcing the network to spread its representation rather than rely on fragile co-adaptations. It acts like training an ensemble of subnetworks and sharply reduces overfitting.",ideas:["Randomly drop units each training step","Approximates averaging many thinned networks","Weights scaled at test time to match expectations","Strong, cheap regularizer for dense layers"],steps:[{title:"Start with the full layer",detail:"Take the dense activations of a hidden layer during training.",block:0},{title:"Sample a random mask",detail:"For each unit, keep it with probability p or zero it for this step.",block:1},{title:"Forward the thinned net",detail:"Only surviving units pass activations, so each step trains a different subnetwork.",block:2},{title:"Force redundancy",detail:"No unit can rely on a specific partner, spreading the representation broadly.",block:2},{title:"Scale at test time",detail:"Use all units but multiply by p, approximating the average over subnetworks.",block:3}],diagram:"flow",flow:["Full layer","Random mask","Thinned subnet","Scale at test time"]},{id:"batchnorm",title:"Batch Normalization: Accelerating Deep Network Training",authors:"Ioffe, Szegedy",year:2015,venue:"ICML",topic:"Regularization",difficulty:"Intermediate",link:"https://arxiv.org/abs/1502.03167",summary:"Batch norm normalizes each layer activation using mini-batch statistics, stabilizing the distribution that later layers must learn from. It lets you train faster with higher learning rates and less careful initialization.",ideas:["Normalize activations per mini-batch to zero mean, unit variance","Learnable scale and shift restore representational power","Allows higher learning rates and faster convergence","Acts as a mild regularizer"],steps:[{title:"Collect layer activations",detail:"Take the pre-activation values for the current mini-batch.",block:0},{title:"Compute batch statistics",detail:"Find the per-feature mean and variance across the batch.",block:1},{title:"Normalize the activations",detail:"Subtract the mean and divide by the standard deviation to get zero mean, unit variance.",block:1},{title:"Scale and shift",detail:"Apply learnable gamma and beta so the layer can recover any useful distribution.",block:2},{title:"Track running stats",detail:"Keep moving averages of mean and variance to normalize consistently at inference.",block:3}],diagram:"flow",flow:["Activations","Normalize (batch stats)","Scale + shift","Next layer"]},{id:"dqn",title:"Playing Atari with Deep Reinforcement Learning",authors:"Mnih, Kavukcuoglu, Silver, et al.",year:2013,venue:"NeurIPS Workshop",topic:"Reinforcement",difficulty:"Advanced",link:"https://arxiv.org/abs/1312.5602",summary:"The Deep Q-Network learned to play Atari games straight from raw pixels, matching or beating humans on many titles. It showed that deep nets could approximate value functions in reinforcement learning at scale.",ideas:["CNN maps screen pixels to action values","Experience replay decorrelates training samples","Target network stabilizes the Q-learning updates","One architecture learns many games from reward alone"],steps:[{title:"Stack raw frames",detail:"Feed the last few grayscale screens so motion is visible to the network.",block:0},{title:"Estimate action values",detail:"A CNN maps the pixel state to a Q-value for every possible action.",block:1},{title:"Choose epsilon-greedy",detail:"Mostly pick the best action, sometimes explore at random.",block:3},{title:"Store the transition",detail:"Save (state, action, reward, next state) into a replay buffer.",block:4},{title:"Replay random batches",detail:"Sample past transitions to decorrelate updates and reuse experience.",block:4},{title:"Regress toward the target",detail:"Fit Q toward reward plus discounted max next-Q from a slowly updated target net.",block:2}],diagram:"flow",flow:["Pixels","CNN Q-network","Action values","Epsilon-greedy action","Replay buffer"]},{id:"unet",title:"U-Net: Convolutional Networks for Biomedical Image Segmentation",authors:"Ronneberger, Fischer, Brox",year:2015,venue:"MICCAI",topic:"Vision",difficulty:"Intermediate",link:"https://arxiv.org/abs/1505.04597",summary:"U-Net pairs a contracting encoder with a symmetric expanding decoder and skip connections that carry fine detail across. It delivers precise pixel-level segmentation from very few training images and remains a default for dense prediction.",ideas:["Encoder downsamples to capture context","Decoder upsamples to recover resolution","Skip connections fuse high-res encoder features","Strong results from few labeled images via augmentation"],steps:[{title:"Contract with the encoder",detail:"Repeated conv plus max-pool halves resolution and grows the receptive field.",block:"enc"},{title:"Reach the bottleneck",detail:"The lowest level holds the most abstract, global context of the image.",block:"bottleneck"},{title:"Expand with the decoder",detail:"Up-convolutions double resolution back toward the original image size.",block:"dec"},{title:"Fuse skip connections",detail:"Concatenate matching encoder features so fine spatial detail is restored.",block:"skip"},{title:"Predict the dense mask",detail:"A 1x1 conv assigns a class to every output pixel.",block:"dec"},{title:"Train from few images",detail:"Heavy elastic augmentation makes the net learn from a handful of labeled scans.",block:"enc"}],diagram:"unet"},{id:"gpt3",title:"Language Models are Few-Shot Learners",authors:"Brown, Mann, Ryder, et al.",year:2020,venue:"NeurIPS",topic:"Language",difficulty:"Advanced",link:"https://arxiv.org/abs/2005.14165",summary:"GPT-3 scaled an autoregressive Transformer to 175 billion parameters and showed that a single frozen model could perform new tasks from a few examples in its prompt. In-context learning reframed how we use large language models.",ideas:["Autoregressive next-token prediction at massive scale","Few-shot and zero-shot learning via the prompt alone","No gradient updates needed to adapt to new tasks","Capabilities emerge smoothly with model and data size"],steps:[{title:"Build the prompt",detail:"Describe the task and optionally include a few worked examples in plain text.",block:0},{title:"Run the decoder-only model",detail:"A 175B-parameter autoregressive Transformer reads the whole prompt as context.",block:1},{title:"Learn in context",detail:"The model infers the pattern from the examples without any weight updates.",block:1},{title:"Predict the next token",detail:"Output a probability distribution over the vocabulary for the next token.",block:2},{title:"Generate the completion",detail:"Sample tokens one at a time, feeding each back in, to produce the answer.",block:3}],diagram:"flow",flow:["Prompt + examples","Decoder-only Transformer","Next-token distribution","Generated completion"]},{id:"seq2seq",title:"Sequence to Sequence Learning with Neural Networks",authors:"Sutskever, Vinyals, Le",year:2014,venue:"NeurIPS",topic:"Language",difficulty:"Intermediate",link:"https://arxiv.org/abs/1409.3215",summary:"Seq2Seq read a whole input sequence into a fixed vector with one LSTM, then generated the output sequence with a second LSTM. It made end-to-end neural machine translation work and set the encoder-decoder template that attention and Transformers later refined.",ideas:["Encoder LSTM compresses the source into a thought vector","Decoder LSTM unrolls that vector into the target sequence","Reversing the source word order eased optimization","One model handles variable-length input and output"],steps:[{title:"Read the source tokens",detail:"Feed the input words one at a time into the encoder LSTM.",block:"enc"},{title:"Compress to a thought vector",detail:"The encoder hidden state after the last token summarizes the whole input.",block:"enc"},{title:"Reverse the source order",detail:"Reading the input backwards shortens early dependencies and eased optimization.",block:"enc"},{title:"Seed the decoder",detail:"Initialize the decoder LSTM with that fixed-length thought vector.",block:"dec"},{title:"Generate the target",detail:"Emit one output token per step, feeding each prediction back as the next input.",block:"dec"}],diagram:"seq2seq"},{id:"gru",title:"Learning Phrase Representations with RNN Encoder-Decoder",authors:"Cho, van Merrienboer, Bahdanau, et al.",year:2014,venue:"EMNLP",topic:"Language",difficulty:"Intermediate",link:"https://arxiv.org/abs/1406.1078",summary:"This paper introduced the GRU, a gated recurrent unit that controls memory with reset and update gates and far fewer parameters than an LSTM. It also framed the RNN encoder-decoder used for scoring and generating translations.",ideas:["Update gate decides how much past state to keep","Reset gate decides how much past state to forget","Fewer gates than LSTM, cheaper to train","Encoder-decoder learns phrase-level representations"],steps:[{title:"Take input and prior state",detail:"Each step sees the current token x_t and the previous hidden state.",block:0},{title:"Compute the reset gate",detail:"Decide how much of the past state to forget when forming a candidate.",block:1},{title:"Compute the update gate",detail:"Decide how much old state to keep versus how much new candidate to admit.",block:1},{title:"Form the candidate state",detail:"Blend the reset-gated history with the new input into a proposed state.",block:2},{title:"Produce the new hidden state",detail:"Interpolate old and candidate by the update gate to get h_t.",block:3}],diagram:"flow",flow:["Input x_t","Reset + update gates","Candidate state","New hidden state h_t"]},{id:"attention",title:"Neural Machine Translation by Jointly Learning to Align and Translate",authors:"Bahdanau, Cho, Bengio",year:2014,venue:"ICLR",topic:"Language",difficulty:"Intermediate",link:"https://arxiv.org/abs/1409.0473",summary:"Bahdanau attention let the decoder look back at every encoder state and weight them per output word, instead of relying on a single fixed vector. It fixed the bottleneck in plain Seq2Seq and is the direct ancestor of self-attention.",ideas:["Decoder computes alignment scores over all encoder states","Softmax turns scores into a context-weighting distribution","Context vector is a weighted sum of encoder states","Removes the fixed-length encoding bottleneck"],steps:[{title:"Encode every source position",detail:"A bidirectional RNN produces one annotation vector per input word.",block:"enc"},{title:"Score alignment per output",detail:"For each decoder step, score how well each encoder state matches the current need.",block:"attn"},{title:"Softmax the scores",detail:"Turn alignment scores into attention weights that sum to one.",block:"attn"},{title:"Build the context vector",detail:"Take a weighted sum of encoder states using those attention weights.",block:"attn"},{title:"Decode with context",detail:"Feed the per-step context plus prior output into the decoder, dropping the fixed bottleneck.",block:"dec"}],diagram:"seq2seq"},{id:"vae",title:"Auto-Encoding Variational Bayes",authors:"Kingma, Welling",year:2013,venue:"ICLR",topic:"Generative",difficulty:"Advanced",link:"https://arxiv.org/abs/1312.6114",summary:"The VAE pairs an encoder that maps data to a distribution over latent codes with a decoder that reconstructs from samples of that latent. The reparameterization trick makes the sampling differentiable, so the whole model trains with backprop.",ideas:["Encoder outputs a mean and variance over latent z","Reparameterization trick keeps sampling differentiable","ELBO balances reconstruction against a prior on z","Smooth latent space supports generation and interpolation"],steps:[{title:"Encode to a distribution",detail:"The encoder maps input x to a mean and variance over the latent z.",block:"enc"},{title:"Output mu and sigma",detail:"Rather than a point, the encoder describes a Gaussian over latent codes.",block:"params"},{title:"Reparameterize the sample",detail:"Sample z = mu + sigma * epsilon so gradients flow through the randomness.",block:"z"},{title:"Decode to reconstruct",detail:"The decoder turns the sampled z back into a reconstruction of x.",block:"dec"},{title:"Optimize the ELBO",detail:"Balance reconstruction quality against a KL term pulling z toward the prior.",block:"dec"}],diagram:"vae"},{id:"layernorm",title:"Layer Normalization",authors:"Ba, Kiros, Hinton",year:2016,venue:"arXiv",topic:"Regularization",difficulty:"Intermediate",link:"https://arxiv.org/abs/1607.06450",summary:"Layer norm normalizes across the features of a single example rather than across the batch, so it works the same at any batch size and inside recurrent steps. It became the normalization of choice inside Transformers.",ideas:["Normalize over feature dimensions, not the batch","Independent of batch size, works with batch size one","Learnable gain and bias restore expressiveness","Stabilizes RNNs and Transformer blocks"],steps:[{title:"Take one example vector",detail:"Operate on the feature vector of a single token or sample.",block:0},{title:"Compute per-example stats",detail:"Find the mean and variance across that vector's features, not the batch.",block:1},{title:"Normalize the features",detail:"Center and scale to zero mean and unit variance, independent of batch size.",block:2},{title:"Apply gain and bias",detail:"Learnable gamma and beta restore representational flexibility.",block:3}],diagram:"flow",flow:["Feature vector","Mean + variance per example","Normalize","Gain + bias"]},{id:"ddpm",title:"Denoising Diffusion Probabilistic Models",authors:"Ho, Jain, Abbeel",year:2020,venue:"NeurIPS",topic:"Generative",difficulty:"Advanced",link:"https://arxiv.org/abs/2006.11239",summary:"DDPM defines a forward process that gradually adds Gaussian noise to data and trains a network to reverse it step by step. Sampling starts from pure noise and denoises into a sharp image, making diffusion competitive with GANs for high-fidelity generation.",ideas:["Forward process slowly corrupts data into Gaussian noise","Network learns to predict the noise at each step","Reverse sampling denoises from noise back to data","Simple regression loss, stable training, sharp samples"],steps:[{title:"Define the forward noising",detail:"A fixed Markov chain adds a little Gaussian noise at each of T steps.",block:"forward"},{title:"Corrupt to pure noise",detail:"After enough steps the data is indistinguishable from standard Gaussian noise.",block:"forward"},{title:"Train a denoiser",detail:"A U-Net learns to predict the noise added at a randomly sampled timestep.",block:"predict"},{title:"Use a simple loss",detail:"Mean-squared error between predicted and true noise gives stable training.",block:"predict"},{title:"Sample by reversing",detail:"Start from noise and apply the learned denoiser step by step back to a sharp image.",block:"reverse"}],diagram:"diffusion"},{id:"vit",title:"An Image is Worth 16x16 Words: Transformers for Image Recognition at Scale",authors:"Dosovitskiy, Beyer, Kolesnikov, et al.",year:2020,venue:"ICLR",topic:"Vision",difficulty:"Advanced",link:"https://arxiv.org/abs/2010.11929",summary:"The Vision Transformer cuts an image into fixed patches, embeds each as a token, and feeds the sequence to a plain Transformer encoder. With enough pre-training data it matches or beats CNNs, showing convolutions are not required for strong vision models.",ideas:["Split image into fixed-size patches as tokens","Linear patch embeddings plus position embeddings","A class token aggregates a global representation","Standard Transformer encoder, no convolutions"],steps:[{title:"Split into patches",detail:"Cut the image into a grid of fixed 16x16 patches, each treated as a token.",block:"patches"},{title:"Linearly embed each patch",detail:"Flatten and project every patch to a token embedding vector.",block:"embed"},{title:"Add position embeddings",detail:"Learned position vectors tell the encoder where each patch sat in the grid.",block:"embed"},{title:"Prepend a class token",detail:"A learnable CLS token will gather the global image representation.",block:"embed"},{title:"Run the Transformer encoder",detail:"A standard self-attention stack mixes information across all patches.",block:"encoder"},{title:"Classify from the class token",detail:"An MLP head reads the final CLS vector to predict the label.",block:"encoder"}],diagram:"vit"},{id:"clip",title:"Learning Transferable Visual Models from Natural Language Supervision",authors:"Radford, Kim, Hallacy, et al.",year:2021,venue:"ICML",topic:"Multimodal",difficulty:"Advanced",link:"https://arxiv.org/abs/2103.00020",summary:"CLIP trains an image encoder and a text encoder together so matching image-caption pairs land close in a shared space. The result is zero-shot classification: name the classes in words and the model scores images against them without task-specific training.",ideas:["Dual encoders for images and text","Contrastive loss aligns matching pairs, repels mismatches","Trained on 400M web image-text pairs","Zero-shot transfer via natural-language class prompts"],steps:[{title:"Gather image-text pairs",detail:"Collect 400M images each with its natural-language caption from the web.",block:"imgenc"},{title:"Encode both modalities",detail:"An image encoder and a text encoder each produce an embedding vector.",block:"textenc"},{title:"Project to shared space",detail:"Map both embeddings into one joint space where they can be compared.",block:"align"},{title:"Contrast pairs in a batch",detail:"Pull matching image-text pairs together and push mismatches apart.",block:"align"},{title:"Classify zero-shot",detail:"Phrase class names as text prompts and score an image against each.",block:"shared"}],diagram:"clip"},{id:"lora",title:"LoRA: Low-Rank Adaptation of Large Language Models",authors:"Hu, Shen, Wallis, et al.",year:2021,venue:"ICLR",topic:"Fine-tuning",difficulty:"Intermediate",link:"https://arxiv.org/abs/2106.09685",summary:"LoRA freezes a pretrained model and learns small low-rank update matrices injected into its weights, cutting the trainable parameters by orders of magnitude. It makes fine-tuning huge models cheap and the adapters easy to swap.",ideas:["Freeze base weights, learn a low-rank delta W = BA","Trainable parameters drop by 10000x for large models","No extra inference latency once merged","Swappable per-task adapters over one shared backbone"],steps:[{title:"Freeze the base weights",detail:"Keep the large pretrained weight matrix W fixed during fine-tuning.",block:0},{title:"Inject a low-rank delta",detail:"Add a small update B times A, where B and A are skinny matrices of rank r.",block:1},{title:"Train only A and B",detail:"Update just the adapter matrices, cutting trainable parameters by orders of magnitude.",block:2},{title:"Merge for inference",detail:"Fold B times A back into W so there is no extra latency at serving time.",block:3},{title:"Swap adapters per task",detail:"Keep one shared backbone and load a different tiny adapter for each task.",block:3}],diagram:"flow",flow:["Frozen weight W","Add low-rank B x A","Train only A, B","Merge for inference"]},{id:"instructgpt",title:"Training Language Models to Follow Instructions with Human Feedback",authors:"Ouyang, Wu, Jiang, et al.",year:2022,venue:"NeurIPS",topic:"Alignment",difficulty:"Advanced",link:"https://arxiv.org/abs/2203.02155",summary:"InstructGPT aligns a language model to human intent by collecting preference data, training a reward model, and fine-tuning with reinforcement learning. The RLHF recipe made models far more helpful and honest, and underpins modern chat assistants.",ideas:["Supervised fine-tuning on human demonstrations","Reward model trained from ranked output comparisons","PPO optimizes the policy against that reward","Smaller aligned models preferred over larger raw ones"],steps:[{title:"Collect demonstrations",detail:"Humans write ideal responses to a range of prompts.",block:"demo"},{title:"Supervised fine-tune",detail:"Fine-tune the base model on those demonstrations to follow instructions.",block:"sft"},{title:"Rank model outputs",detail:"Humans order several sampled responses from best to worst.",block:"rm"},{title:"Train a reward model",detail:"Fit a model that scores responses to match the human rankings.",block:"rm"},{title:"Optimize with PPO",detail:"Reinforcement learning tunes the policy to maximize the learned reward.",block:"ppo"},{title:"Stay close to the base",detail:"A KL penalty keeps the policy near the SFT model to avoid reward hacking.",block:"ppo"}],diagram:"rlhf"},{id:"chinchilla",title:"Training Compute-Optimal Large Language Models",authors:"Hoffmann, Borgeaud, Mensch, et al.",year:2022,venue:"NeurIPS",topic:"Scaling",difficulty:"Intermediate",link:"https://arxiv.org/abs/2203.15556",summary:"The Chinchilla study showed that for a fixed compute budget, model size and training tokens should grow in roughly equal proportion. Most prior models were oversized and undertrained, and a smaller model on more data beat them.",ideas:["Scale parameters and tokens together, not just size","Roughly 20 training tokens per parameter is near-optimal","A 70B model on 1.4T tokens beat much larger peers","Reframed scaling laws toward data, not just parameters"],steps:[{title:"Fix a compute budget",detail:"Decide how many FLOPs you can spend on a single training run.",block:0},{title:"Sweep size vs tokens",detail:"Train many models trading parameter count against training tokens.",block:1},{title:"Fit the scaling law",detail:"The data shows roughly 20 tokens per parameter minimizes loss at fixed compute.",block:1},{title:"Train compute-optimal",detail:"Pick a smaller model trained on far more tokens than prior practice.",block:2},{title:"Beat larger peers",detail:"A 70B model on 1.4T tokens outperformed much bigger, undertrained models.",block:3}],diagram:"flow",flow:["Fixed compute","Balance params vs tokens","Train compute-optimal","Smaller, better model"]},{id:"alphago",title:"Mastering the Game of Go with Deep Neural Networks and Tree Search",authors:"Silver, Huang, Maddison, et al.",year:2016,venue:"Nature",topic:"Reinforcement",difficulty:"Advanced",link:e("Mastering the game of Go with deep neural networks and tree search Silver Nature"),summary:"AlphaGo combined policy and value networks with Monte Carlo tree search to defeat a world-champion Go player, a feat long thought decades away. It proved deep learning plus search could crack search spaces vastly larger than chess.",ideas:["Policy network proposes promising moves","Value network estimates who is winning","Monte Carlo tree search guided by both networks","Self-play reinforcement learning sharpens the policy"],steps:[{title:"Read the board state",detail:"Encode the current Go position as input planes for the networks.",block:0},{title:"Propose moves",detail:"The policy network narrows the huge action space to a few promising moves.",block:1},{title:"Evaluate positions",detail:"The value network estimates the probability of winning from a position.",block:2},{title:"Search with MCTS",detail:"Monte Carlo tree search expands the most promising lines guided by both networks.",block:3},{title:"Pick the best move",detail:"Choose the move with the strongest search statistics.",block:4},{title:"Improve by self-play",detail:"Reinforcement learning on games against itself keeps sharpening the policy.",block:1}],diagram:"flow",flow:["Board state","Policy net (moves)","Value net (win prob)","MCTS rollouts","Best move"]},{id:"gpt1",title:"Improving Language Understanding by Generative Pre-Training",authors:"Radford, Narasimhan, Salimans, Sutskever",year:2018,venue:"OpenAI",topic:"Language",difficulty:"Advanced",link:e("Improving Language Understanding by Generative Pre-Training Radford"),summary:"The first GPT pre-trained a left-to-right Transformer decoder to predict the next token on a large unlabeled corpus, then fine-tuned the same weights on each downstream task with a tiny added head. It showed that one generatively pre-trained model could transfer broadly, the recipe later scaled into GPT-2 and GPT-3.",ideas:["Unsupervised next-token pre-training on plain text","A single decoder-only Transformer reused across tasks","Task-specific fine-tuning with a small linear head","Input transformations let one model handle varied formats"],steps:[{title:"Pre-train on raw text",detail:"Train a Transformer decoder to predict the next token over a large unlabeled corpus.",block:0},{title:"Read left to right",detail:"Masked self-attention lets each token see only earlier positions, so the model is a true language model.",block:1},{title:"Reframe each task as a sequence",detail:"Wrap inputs with delimiter tokens so classification, entailment, and similarity all become one token stream.",block:2},{title:"Add a small task head",detail:"Attach a linear layer on the final token state for the downstream label.",block:3},{title:"Fine-tune end to end",detail:"Update all weights on the labeled data, keeping the language-model loss as an auxiliary signal.",block:3}],diagram:"flow",flow:["Raw text","Decoder pre-training","Task as token stream","Fine-tune with small head"]},{id:"lstm",title:"Long Short-Term Memory",authors:"Hochreiter, Schmidhuber",year:1997,venue:"Neural Computation",topic:"Language",difficulty:"Intermediate",link:e("Long Short-Term Memory Hochreiter Schmidhuber 1997"),summary:"The LSTM added a protected memory cell with input, forget, and output gates so gradients could flow across many time steps without vanishing. It made recurrent networks able to learn long-range dependencies and powered a decade of sequence modeling before Transformers.",ideas:["A cell state carries memory across time with little decay","Input gate controls what new information enters the cell","Forget gate decides what stored memory to discard","Output gate exposes a filtered view of the cell as the hidden state"],steps:[{title:"Receive input and prior memory",detail:"Each step sees the token x_t, the previous hidden state, and the previous cell state.",block:0},{title:"Compute the forget gate",detail:"A sigmoid decides, per element, how much of the old cell state to keep.",block:1},{title:"Compute the input gate",detail:"Another sigmoid plus a tanh candidate decide what new information to write into the cell.",block:1},{title:"Update the cell state",detail:"Scale the old cell by the forget gate and add the gated candidate, giving a near-linear memory path.",block:2},{title:"Emit the hidden state",detail:"The output gate filters a tanh of the cell to produce h_t for the next step and any readout.",block:3}],diagram:"flow",flow:["Input x_t","Forget + input gates","Update cell state","Output gate -> h_t"]},{id:"flashattention",title:"FlashAttention: Fast and Memory-Efficient Exact Attention with IO-Awareness",authors:"Dao, Fu, Ermon, et al.",year:2022,venue:"NeurIPS",topic:"Systems",difficulty:"Advanced",link:"https://arxiv.org/abs/2205.14135",summary:"FlashAttention computes exact attention without ever writing the full N-by-N score matrix to memory. By tiling the computation and keeping a running softmax in fast on-chip SRAM, it slashes memory traffic and runs several times faster, letting models handle far longer sequences.",ideas:["Avoid materializing the full attention matrix in HBM","Tile queries and keys, stream tiles through on-chip SRAM","Online softmax keeps a running max and sum across tiles","IO-aware design is bandwidth-bound, not compute-bound"],steps:[{title:"Split into blocks",detail:"Partition the queries, keys, and values into tiles small enough to fit in fast on-chip memory.",block:"tile"},{title:"Stream key/value tiles",detail:"For each query tile, loop over key-value tiles instead of loading all keys at once.",block:"tile"},{title:"Keep an online softmax",detail:"Track a running max and running denominator so the softmax stays exact and numerically stable across tiles.",block:"softmax"},{title:"Rescale the accumulator",detail:"When a new tile shifts the max, rescale the partial output so earlier contributions stay correctly weighted.",block:"softmax"},{title:"Write each output once",detail:"Only the final per-query output ever touches slow memory, cutting IO and avoiding the N-by-N matrix entirely.",block:"out"}],diagram:"flow",flow:["Tile Q, K, V","Stream KV through SRAM","Online softmax rescale","Write output once"]},{id:"switch-transformer",title:"Switch Transformers: Scaling to Trillion Parameter Models",authors:"Fedus, Zoph, Shazeer",year:2021,venue:"JMLR",topic:"Architecture",difficulty:"Advanced",link:"https://arxiv.org/abs/2101.03961",summary:"Switch Transformers replace the dense feed-forward block with a large bank of expert networks and route each token to just one expert. The model grows to trillions of parameters while the compute per token stays nearly flat, trading memory for capacity.",ideas:["Mixture-of-experts replaces the dense feed-forward layer","A router sends each token to a single top-1 expert","Parameter count scales without scaling per-token compute","A load-balancing loss keeps experts evenly used"],steps:[{title:"Score the experts",detail:"A small router network reads each token and produces a score for every expert.",block:"route"},{title:"Pick the top expert",detail:"Send the token to just the single highest-scoring expert, keeping compute sparse.",block:"route"},{title:"Run the chosen expert",detail:"Only one feed-forward expert processes the token, so per-token cost barely grows with the expert count.",block:"expert"},{title:"Balance the load",detail:"An auxiliary loss penalizes uneven routing so no expert is overloaded or starved.",block:"expert"},{title:"Combine and continue",detail:"Scale the expert output by the router weight and pass it on, scaling capacity into the trillions.",block:"out"}],diagram:"flow",flow:["Token","Router scores experts","Top-1 expert runs","Weighted output"]},{id:"glove",title:"GloVe: Global Vectors for Word Representation",authors:"Pennington, Socher, Manning",year:2014,venue:"EMNLP",topic:"Language",difficulty:"Beginner",link:e("GloVe Global Vectors for Word Representation Pennington Manning"),summary:"GloVe learns word vectors by fitting them directly to global co-occurrence counts rather than scanning local windows one at a time. It blends the statistics of count-based methods with the linear analogy structure of prediction-based embeddings.",ideas:["Build a global word-word co-occurrence matrix","Fit vectors so their dot product matches log co-occurrence","A weighting function downweights rare and frequent pairs","Ratios of co-occurrence encode meaning as vector offsets"],steps:[{title:"Count co-occurrences",detail:"Scan the corpus once to build a matrix of how often each word appears near each other word.",block:0},{title:"Target the log counts",detail:"Train two vectors per word so their dot product plus biases approximates the log of the co-occurrence count.",block:1},{title:"Weight the pairs",detail:"A weighting function damps very rare pairs and caps very frequent ones so neither dominates the fit.",block:2},{title:"Minimize weighted least squares",detail:"Optimize the squared error between predicted and actual log counts across all observed pairs.",block:2},{title:"Read off analogies",detail:"The learned offsets capture analogies linearly, like the prediction-based embeddings but from global statistics.",block:3}],diagram:"flow",flow:["Co-occurrence matrix","Fit dot product to log counts","Weighted least squares","Word vectors"]},{id:"t5",title:"Exploring the Limits of Transfer Learning with a Unified Text-to-Text Transformer",authors:"Raffel, Shazeer, Roberts, et al.",year:2019,venue:"JMLR",topic:"Language",difficulty:"Advanced",link:"https://arxiv.org/abs/1910.10683",summary:"T5 casts every NLP problem as text-in, text-out, so translation, summarization, classification, and question answering all share one model, loss, and decoding procedure. A careful study of objectives and data sizes set a strong template for transfer learning.",ideas:["Frame every task as text-to-text generation","One encoder-decoder Transformer for all problems","Span-corruption pre-training on a large cleaned corpus","A task prefix tells the model what to do"],steps:[{title:"Phrase the task as text",detail:"Prepend a prefix such as translate or summarize so the input fully describes the desired output.",block:0},{title:"Pre-train by span corruption",detail:"Mask contiguous spans of text and train the model to generate the missing spans.",block:1},{title:"Encode then decode",detail:"A standard encoder-decoder reads the prompt and generates the answer token by token.",block:2},{title:"Share one objective",detail:"Because every task is generation, a single cross-entropy loss trains them all the same way.",block:2},{title:"Fine-tune or multitask",detail:"Adapt the shared model to a task, or train on many tasks at once, with no architecture changes.",block:3}],diagram:"flow",flow:["Task prefix + input","Span-corruption pre-train","Encoder-decoder","Generated text answer"]}];export{a as P};
